import React, { useState } from "react";

const SendEmailPage = () => {
  const [subject, setSubject] = useState("");
  const [template, setTemplate] = useState("promo");
  const [sending, setSending] = useState(false);
  const [message, setMessage] = useState("");

  const handleSend = async () => {
    setSending(true);
    setMessage("");

    const token = localStorage.getItem("adminToken");

    const res = await fetch("http://localhost:5000/api/email/send", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({
        template,
        subject,
      }),
    });

    const data = await res.json();
    setSending(false);
    setMessage(data.message);
  };

  return (
    <div className="p-8">
      <h1 className="text-3xl font-bold text-[#e06c7f] mb-8">📩 Gửi Email Marketing</h1>

      {/* Main container */}
      <div className="bg-white p-6 rounded-xl shadow-lg max-w-2xl">

        {/* Subject */}
        <label className="font-medium">Tiêu đề Email</label>
        <input
          className="w-full border p-3 rounded-lg mb-4"
          placeholder="Nhập tiêu đề email"
          value={subject}
          onChange={(e) => setSubject(e.target.value)}
        />

        {/* Template select */}
        <label className="font-medium">Chọn mẫu email 📌</label>
        <select
          className="w-full border p-3 rounded-lg mb-4"
          value={template}
          onChange={(e) => setTemplate(e.target.value)}
        >
          <option value="promo">🎁 Khuyến mãi</option>
          <option value="holiday">🎄 Dịp lễ / năm mới</option>
          <option value="birthday">🎂 Sinh nhật</option>
          <option value="valentine">❤️ Valentine</option>
          <option value="women">💐 20/10 / 8/3</option>
          <option value="custom">✍️ Tự nhập nội dung</option>
        </select>

        <button
          onClick={handleSend}
          disabled={sending}
          className="w-full py-3 bg-[#e06c7f] hover:bg-[#d35d75] text-white font-semibold rounded-lg"
        >
          {sending ? "Đang gửi email..." : "📨 Gửi Email"}
        </button>

        {message && (
          <div className="mt-4 p-3 bg-green-100 border border-green-300 text-green-700 rounded-lg">
            ✔ {message}
          </div>
        )}
      </div>

      {/* Preview Box */}
      <div className="mt-8 p-6 bg-[#faf8f6] border border-[#f0e8e3] rounded-xl">
        <h2 className="text-xl font-semibold mb-3">📌 Preview email</h2>

        <p className="text-gray-600">
          Hiển thị bản xem trước của template ở đây (tùy backend gửi template).
        </p>
      </div>
    </div>
  );
};

export default SendEmailPage;
